def normalize_header_value(value: str) -> str:
    """Normalize a header value by stripping whitespace."""
    # BUG: uses upper() instead of preserving case after stripping
    return value.strip().upper()

def strip_quotes(value: str) -> str:
    if value.startswith('"') and value.endswith('"'):
        return value[1:-1]
    return value

def casefold_keys(d: dict) -> dict:
    """Return a new dict with all keys lowercased."""
    return {k.casefold(): v for k, v in d.items()}
